module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

wire [7:0] mul_a_ext = {{4{1'b0}}, mul_a};
wire [7:0] mul_b_ext = {{4{1'b0}}, mul_b};

reg [7:0] partial_product[3:0];

genvar i;
generate
    for(i = 0; i < 4; i=i+1) begin : gen_partial_products
        assign partial_product[i] = (mul_b_ext[i]) ? (mul_a_ext << i) : 'd0;
    end
endgenerate

reg [7:0] sum_tmp1, sum_tmp2;

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum_tmp1 <= 'd0;
        sum_tmp2 <= 'd0;
    end else begin
        sum_tmp1 <= (mul_b_ext[0] ? mul_a_ext : 0) + (mul_b_ext[1] ? mul_a_ext << 1 : 0);
        sum_tmp2 <= (mul_b_ext[2] ? mul_a_ext << 2 : 0) + (mul_b_ext[3] ? mul_a_ext << 3 : 0);
    end
end

reg [N-1:0] final_sum;

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        final_sum <= 'd0;
    end else begin
        final_sum <= sum_tmp1 + sum_tmp2;
    end
end

assign mul_out = final_sum;

endmodule
